@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h1>Kanban Board</h1>

@if (_loading)
{
    <div class="alert alert-info">Loading tasks…</div>
}
else if (_error is not null)
{
    <div class="alert alert-danger">@_error</div>
}
else
{
    <!-- Stats bar -->
    <div class="stats-bar d-flex gap-3 mb-3 flex-wrap">
        <span class="badge bg-secondary">Total: @_allTasks.Count</span>
        <span class="badge bg-primary">To Do: @GetColumn("To Do").Count</span>
        <span class="badge bg-warning text-dark">In Progress: @GetColumn("In Progress").Count</span>
        <span class="badge bg-success">Done: @GetColumn("Done").Count</span>
        <span class="badge bg-danger">Overdue: @_allTasks.Count(t => t.DueDate.Date < DateTime.Today)</span>
    </div>

    <!-- Search bar -->
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Search tasks by title…"
               @bind="_searchText" @bind:event="oninput" />
    </div>

    <!-- Kanban columns -->
    <div class="board-columns d-flex gap-3">
        @foreach (var status in _statuses)
        {
            var columnTasks = GetFilteredColumn(status);
            var statusIndex = Array.IndexOf(_statuses, status);

            <div class="board-column card flex-fill">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <strong>@status</strong>
                    <span class="badge bg-secondary rounded-pill">@columnTasks.Count</span>
                </div>
                <div class="card-body d-flex flex-column gap-2">
                    @foreach (var task in columnTasks)
                    {
                        <div class="task-card card">
                            <div class="card-body p-2">
                                <h6 class="card-title mb-1">@task.Title</h6>
                                <p class="card-text mb-1 text-muted small">@task.Assignee</p>
                                <div class="d-flex justify-content-between align-items-center mb-1">
                                    <span class="badge @GetPriorityClass(task.Priority)">@task.Priority</span>
                                    <small class="text-muted">@task.DueDate.ToString("MMM dd")</small>
                                </div>
                                <div class="d-flex gap-1">
                                    @if (statusIndex > 0)
                                    {
                                        var leftStatus = _statuses[statusIndex - 1];
                                        <button class="btn btn-outline-secondary btn-sm"
                                                disabled="@_moving"
                                                @onclick="() => MoveTaskAsync(task.Id, leftStatus)">
                                            ← Move Left
                                        </button>
                                    }
                                    @if (statusIndex < _statuses.Length - 1)
                                    {
                                        var rightStatus = _statuses[statusIndex + 1];
                                        <button class="btn btn-outline-secondary btn-sm"
                                                disabled="@_moving"
                                                @onclick="() => MoveTaskAsync(task.Id, rightStatus)">
                                            Move Right →
                                        </button>
                                    }
                                </div>
                            </div>
                        </div>
                    }

                    @if (_addingToColumn == status)
                    {
                        <div class="card bg-light">
                            <div class="card-body p-2 d-flex flex-column gap-2">
                                <input type="text" class="form-control form-control-sm"
                                       placeholder="Title" @bind="_newTitle" />
                                <input type="text" class="form-control form-control-sm"
                                       placeholder="Assignee" @bind="_newAssignee" />
                                <select class="form-select form-select-sm" @bind="_newPriority">
                                    <option value="High">High</option>
                                    <option value="Medium">Medium</option>
                                    <option value="Low">Low</option>
                                </select>
                                <input type="date" class="form-control form-control-sm" @bind="_newDueDate" />
                                <div class="d-flex gap-1">
                                    <button class="btn btn-primary btn-sm" disabled="@_saving"
                                            @onclick="() => SaveNewTaskAsync(status)">
                                        Save
                                    </button>
                                    <button class="btn btn-secondary btn-sm" @onclick="CancelAdd">
                                        Cancel
                                    </button>
                                </div>
                            </div>
                        </div>
                    }
                    else
                    {
                        <button class="btn btn-outline-primary btn-sm mt-auto"
                                @onclick="() => StartAdd(status)">
                            + Add Task
                        </button>
                    }
                </div>
            </div>
        }
    </div>
}

