+            _error = $"Failed to load tasks: {ex.Message}";
+        }
+        finally
+        {
+            _loading = false;
+        }
+    }
+
+    private List<TaskItem> GetColumn(string status) =>
+        _allTasks.Where(t => t.Status == status).ToList();
+
+    private List<TaskItem> GetFilteredColumn(string status) =>
+        _allTasks
+            .Where(t => t.Status == status &&
+                        (string.IsNullOrWhiteSpace(_searchText) ||
+                         t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase)))
+            .ToList();
+
+    private static string GetPriorityClass(string priority) => priority switch
+    {
+        "High" => "bg-danger",
+        "Medium" => "bg-warning text-dark",
+        "Low" => "bg-success",
+        _ => "bg-secondary"
+    };
+
+    private async Task MoveTaskAsync(int taskId, string newStatus)
+    {
+        _moving = true;
+        try
+        {
+            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
+            var idx = _allTasks.FindIndex(t => t.Id == taskId);
+            if (idx >= 0)
+            {
+                _allTasks[idx] = _allTasks[idx] with { Status = newStatus };
+            }
+        }
+        catch (Exception ex)
+        {
+            _error = $"Failed to move task: {ex.Message}";
+        }
+        finally
+        {
+            _moving = false;
+        }
+    }
+
+    private void StartAdd(string status)
+    {
+        _addingToColumn = status;
+        _newTitle = string.Empty;
+        _newAssignee = string.Empty;
+        _newPriority = "Medium";
+        _newDueDate = DateTime.Today.AddDays(7);
+    }
+
+    private void CancelAdd() => _addingToColumn = null;
+
+    private async Task SaveNewTaskAsync(string status)
+    {
+        if (string.IsNullOrWhiteSpace(_newTitle))
+            return;
+
+        _saving = true;
+        try
+        {
+            var created = await TaskService.CreateTaskAsync(_newTitle.Trim(), _newAssignee.Trim(), _newPriority, _newDueDate);
+            // If the service returns a different status, update it to match the column
+            if (created.Status != status)
+            {
+                await TaskService.UpdateTaskStatusAsync(created.Id, status);
+                created = created with { Status = status };
+            }
+            _allTasks.Add(created);
+            _addingToColumn = null;
+        }
+        catch (Exception ex)
+        {
+            _error = $"Failed to create task: {ex.Message}";
+        }
+        finally
+        {
+            _saving = false;
+        }
+    }
+}
